const recorder = new Recorder({
  encoderPath: "/opus/encoderWorker.min.js",
  encoderSampleRate: sampleRate,
  numberOfChannels: 1,
  streamPages: false,
  maxFramesPerPage: 1,
  encoderFrameSize: 20,
  encoderApplication: 2048,
  monitorGain: 0,
  recordingGain: 1,
  ondataavailable: (packet) => {
    const bytes =
      packet instanceof Uint8Array
        ? packet
        : packet instanceof ArrayBuffer
        ? new Uint8Array(packet)
        : new Uint8Array(packet.buffer || packet);

    sendPacket?.(bytes);
  },
});